class Terminal {
  constructor() {
    this._el = null;
  }
  open(el) {
    this._el = el;
  }
  write(data) {
    if (!this._el) return;
    const text = typeof data === 'string' ? data : new TextDecoder().decode(data);
    if (this._el.textContent === undefined) {
      this._el.textContent = text;
    } else {
      this._el.textContent += text;
    }
  }
  reset() {
    if (this._el) this._el.textContent = '';
  }
  dispose() {}
}
module.exports = { Terminal };
